"use client"

import { useState } from "react"
import { RealTimePanel } from "./real-time-panel"
import { SimulationPanel } from "./simulation-panel"
import type { ImpactResponse } from "@/lib/types"
import { Activity, Globe2 } from "lucide-react"

interface SidebarProps {
  onImpactUpdate: (data: ImpactResponse) => void
}

export function Sidebar({ onImpactUpdate }: SidebarProps) {
  const [mode, setMode] = useState<"realtime" | "simulation">("realtime")

  return (
    <div className="w-full h-full flex flex-col bg-[#050810] border-l border-slate-800 shadow-2xl">
      {/* Header */}
      <div className="p-6 border-b border-slate-800">
        <h1 className="text-xl font-bold text-white tracking-tight flex items-center gap-2">
          <Globe2 className="text-cyan-500" />
          Solar Impact
        </h1>
        <p className="text-xs text-slate-400 mt-1">Submarine Cable Risk Predictor</p>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-slate-800">
        <button
          onClick={() => setMode("realtime")}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${
            mode === "realtime"
              ? "text-cyan-400 border-b-2 border-cyan-400 bg-cyan-950/10"
              : "text-slate-500 hover:text-slate-300"
          }`}
        >
          Real-Time
        </button>
        <button
          onClick={() => setMode("simulation")}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${
            mode === "simulation"
              ? "text-violet-400 border-b-2 border-violet-400 bg-violet-950/10"
              : "text-slate-500 hover:text-slate-300"
          }`}
        >
          Simulation
        </button>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto">
        {mode === "realtime" ? (
          <RealTimePanel onImpactUpdate={onImpactUpdate} />
        ) : (
          <SimulationPanel onSimulationComplete={onImpactUpdate} />
        )}
      </div>

      {/* Footer / Disclaimer */}
      <div className="p-4 border-t border-slate-800 text-[10px] text-slate-600 leading-tight">
        <p className="mb-2">
          <Activity className="inline w-3 h-3 mr-1" />
          Educational Tool Only
        </p>
        Data sources: NOAA SWPC, NASA DONKI. Risk model is a simplified GIC proxy. Not for operational use.
      </div>
    </div>
  )
}
