"use client"

import { useState } from "react"
import { useMutation } from "@tanstack/react-query"
import type { SimulationResponse } from "@/lib/types"
import { Loader2, Play, Clock, Zap } from "lucide-react"
import { format } from "date-fns"

interface SimulationPanelProps {
  onSimulationComplete: (data: SimulationResponse) => void
}

export function SimulationPanel({ onSimulationComplete }: SimulationPanelProps) {
  const [speed, setSpeed] = useState(1500)
  const [dirLon, setDirLon] = useState(0)
  const [dirLat, setDirLat] = useState(0)
  const [startTime, setStartTime] = useState(new Date().toISOString().slice(0, 16))

  const transitHours = 1.496e8 / speed / 3600

  const simMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/impact/simulate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          startTime: new Date(startTime).toISOString(),
          cmeSpeedKms: speed,
          directionLon: dirLon,
          directionLat: dirLat,
        }),
      })
      if (!res.ok) throw new Error("Simulation failed")
      return res.json()
    },
    onSuccess: (data) => {
      onSimulationComplete(data)
    },
  })

  return (
    <div className="space-y-6 p-4">
      <div className="space-y-4">
        {/* Start Time */}
        <div>
          <label className="block text-xs text-slate-400 mb-1">CME Launch Time (UTC)</label>
          <input
            type="datetime-local"
            value={startTime}
            onChange={(e) => setStartTime(e.target.value)}
            className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-white focus:border-cyan-500 outline-none"
          />
        </div>

        {/* Speed Slider */}
        <div>
          <div className="flex justify-between text-xs mb-1">
            <span className="text-slate-400">CME Speed</span>
            <span className="text-cyan-400 font-mono">{speed} km/s</span>
          </div>
          <input
            type="range"
            min="400"
            max="3000"
            step="50"
            value={speed}
            onChange={(e) => setSpeed(Number(e.target.value))}
            className="w-full accent-cyan-500"
          />
          <div className="text-xs text-slate-500 mt-1 flex items-center gap-1">
            <Clock className="w-3 h-3" /> Est. Transit: {transitHours.toFixed(1)} hours
          </div>
        </div>

        {/* Direction Inputs */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs text-slate-400 mb-1">Impact Lat (°)</label>
            <input
              type="number"
              min="-90"
              max="90"
              value={dirLat}
              onChange={(e) => setDirLat(Number(e.target.value))}
              className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-white focus:border-cyan-500 outline-none"
            />
          </div>
          <div>
            <label className="block text-xs text-slate-400 mb-1">Impact Lon (°)</label>
            <input
              type="number"
              min="-180"
              max="180"
              value={dirLon}
              onChange={(e) => setDirLon(Number(e.target.value))}
              className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-white focus:border-cyan-500 outline-none"
            />
          </div>
        </div>
      </div>

      <button
        onClick={() => simMutation.mutate()}
        disabled={simMutation.isPending}
        className="w-full py-3 bg-violet-600 hover:bg-violet-500 text-white font-bold rounded-md transition-all shadow-[0_0_15px_rgba(124,58,237,0.5)] disabled:opacity-50 flex items-center justify-center gap-2"
      >
        {simMutation.isPending ? (
          <Loader2 className="animate-spin" />
        ) : (
          <>
            <Play className="w-4 h-4" /> RUN SIMULATION
          </>
        )}
      </button>

      {simMutation.data && (
        <div className="bg-slate-900/80 border border-violet-500/30 rounded-lg p-4 animate-in fade-in slide-in-from-bottom-4">
          <h4 className="text-violet-400 text-sm font-bold mb-2 flex items-center gap-2">
            <Zap className="w-4 h-4" /> Simulation Results
          </h4>
          <div className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-slate-400">Arrival:</span>
              <span className="text-white">
                {format(new Date(simMutation.data.predictedArrivalTime), "MMM d, HH:mm")} UTC
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-slate-400">Peak Intensity:</span>
              <span className="text-white font-bold">
                Kp {simMutation.data.syntheticKpPeak.toFixed(1)} ({simMutation.data.gScale})
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-slate-400">Affected Cables:</span>
              <span className="text-white">
                {simMutation.data.cableAggregates.filter((c) => c.maxRisk > 0.2).length}
              </span>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
